computeCode:
(async function(params) {
  const rangeSize = params.width || 100000;
  const offset = params.height || 10000;
  const batchSize = params.param || 500;

  const start = Math.max(2, offset);
  const end = start + rangeSize;

  const startTime = performance.now();
  const primes = [];
  let checksPerformed = 0;
  let compositesFound = 0;
  let batchCount = 0;

  const sieve = new Array(rangeSize + 1).fill(true);
  sieve[0] = sieve[1] = false;

  for (let n = start; n <= end; n++) {
    const localIndex = n - start;

    if (!sieve[localIndex]) {
      compositesFound++;
      continue;
    }

    let isPrime = true;
    const sqrt = Math.sqrt(n);

    for (let i = 2; i <= sqrt; i++) {
      checksPerformed++;
      if (n % i === 0) {
        isPrime = false;
        sieve[localIndex] = false;
        compositesFound++;
        break;
      }
    }

    if (isPrime) {
      primes.push(n);

      for (let multiple = n * 2; multiple <= end; multiple += n) {
        const multipleIndex = multiple - start;
        if (multipleIndex >= 0 && multipleIndex <= rangeSize) {
          sieve[multipleIndex] = false;
        }
      }
    }

    if ((n - start) % batchSize === 0) {
      batchCount++;
      await new Promise(resolve => setTimeout(resolve, 0));
    }
  }

  const took_ms = performance.now() - startTime;
  const numbersChecked = end - start + 1;

  const largestPrime = primes[primes.length - 1];
  const smallestPrime = primes[0];
  const avgGap = primes.length > 1 ? (largestPrime - smallestPrime) / (primes.length - 1) : 0;

  return {
    range: start + '-' + end,
    rangeSize: numbersChecked,
    primesFound: primes.length,
    compositesFound: compositesFound,
    primesDensity: (primes.length / numbersChecked * 100).toFixed(3) + '%',
    smallestPrime,
    largestPrime,
    averageGap: avgGap.toFixed(2),
    checksPerformed,
    batchesProcessed: batchCount,
    took_ms: Math.round(took_ms),
    throughput: numbersChecked / (took_ms / 1000),
    primesPerSecond: Math.round(primes.length / (took_ms / 1000))
  };
})
